class LSMTree:
    def __init__(self, threshold=3):
        self.memtable = {}
        self.threshold = threshold
        self.sstables = []

    def put(self, key, value):
        self.memtable[key] = value
        if len(self.memtable) >= self.threshold:
            self.flush_to_sstable()

    def get(self, key):
        for sstable in reversed(self.sstables):
            if key in sstable:
                return sstable[key]
        return self.memtable.get(key, None)

    def flush_to_sstable(self):
        sstable = SSTable(f'sstable_{len(self.sstables)}.txt')
